package com.example.app.model;
import jakarta.persistence.*;
@Entity
public class BoardItem { @Id @GeneratedValue(strategy = GenerationType.IDENTITY) private Long id; @ManyToOne(optional = false) private Board board; private String title; private String stage; private String priority; private String dueDate; @Column(length = 1200) private String details; public Long getId(){return id;} public Board getBoard(){return board;} public void setBoard(Board board){this.board=board;} public String getTitle(){return title;} public void setTitle(String title){this.title=title;} public String getStage(){return stage;} public void setStage(String stage){this.stage=stage;} public String getPriority(){return priority;} public void setPriority(String priority){this.priority=priority;} public String getDueDate(){return dueDate;} public void setDueDate(String dueDate){this.dueDate=dueDate;} public String getDetails(){return details;} public void setDetails(String details){this.details=details;} }
